const csvRaw = $json.data ?? $json.body ?? $json;

const text = typeof csvRaw === "string"
  ? csvRaw
  : JSON.stringify(csvRaw);

const lines = text
  .split(/\r?\n/)
  .map(line => line.trim())
  .filter(Boolean);

const headers = lines[0]
  .split(",")
  .map(header => header.trim());

const investimentos = lines.slice(1).map(line => {
  const columns = line.split(",").map(column => column.trim());

  const investimento = {};

  headers.forEach((header, index) => {
    investimento[header] = columns[index] ?? "";
  });

  return investimento;
});

return [
  {
    json: {
      investimentos
    }
  }
];

const items = $input.all();

let clientes = [];
let investimentos = [];

for (const item of items) {
  const data = item.json;

  if (Array.isArray(data.clientes)) clientes = data.clientes;
  if (data.body && Array.isArray(data.body.clientes)) clientes = data.body.clientes;
  if (Array.isArray(data.investimentos)) investimentos = data.investimentos;
  if (data.json && Array.isArray(data.json.investimentos)) investimentos = data.json.investimentos;
}

function saldoParaNumero(saldo) {
  if (!saldo) return 0;

  return Number(
    String(saldo)
      .replace("R$", "")
      .replace(/\./g, "")
      .replace(",", ".")
      .trim()
  );
}

function mensagemPorPerfil(cliente, opcoes) {
  const nome = cliente.nome;
  const perfil = cliente.perfil;
  const saldo = cliente.saldo;
  const saldoNumero = saldoParaNumero(saldo);

  const produto = opcoes[0];

  if (!produto) {
    return `Olá, ${nome}. Identificamos seu perfil ${perfil}, mas não encontramos uma opção de investimento compatível neste momento. Recomendamos revisar seu perfil e buscar orientação especializada antes de investir.`;
  }

  const nomeProduto = produto.produto || produto.nome || "produto compatível";
  const rentabilidade = produto.rentabilidade || "rentabilidade informada";
  const minimo = produto.minimo || produto.valor_minimo || "valor mínimo informado";

  if (perfil === "Conservador") {
    return `Olá, ${nome}. Considerando seu perfil conservador e saldo disponível de ${saldo}, a recomendação é priorizar segurança e previsibilidade. Uma opção compatível é ${nomeProduto}, com aplicação mínima de ${minimo} e rentabilidade de ${rentabilidade}.`;
  }

  if (perfil === "Moderado") {
    return `Olá, ${nome}. Considerando seu perfil moderado e saldo disponível de ${saldo}, a recomendação é buscar equilíbrio entre segurança e potencial de retorno. Uma opção compatível é ${nomeProduto}, com aplicação mínima de ${minimo} e rentabilidade de ${rentabilidade}.`;
  }

  if (perfil === "Arrojado") {
    return `Olá, ${nome}. Considerando seu perfil arrojado e saldo disponível de ${saldo}, a recomendação é avaliar oportunidades com maior potencial de retorno, aceitando maior exposição a risco. Uma opção compatível é ${nomeProduto}, com aplicação mínima de ${minimo} e rentabilidade de ${rentabilidade}.`;
  }

  return `Olá, ${nome}. Não foi possível identificar claramente seu perfil de investimento. Recomendamos uma análise individual antes de qualquer decisão.`;
}

const recomendacoes = clientes.map(cliente => {
  const perfil = cliente.perfil;

  const opcoes = investimentos.filter(investimento => {
    return investimento.perfil === perfil;
  });

  return {
    nome: cliente.nome,
    email: cliente.email,
    saldo: cliente.saldo,
    perfil: cliente.perfil,
    mensagem: mensagemPorPerfil(cliente, opcoes),
    opcoes
  };
});

return [
  {
    json: {
      recomendacoes
    }
  }
];

const input = $json;

const recomendacoes =
  input.recomendacoes ||
  input.resultados ||
  input.body?.recomendacoes ||
  [];

function parseBRL(valor) {
  if (!valor) return 0;

  return Number(
    String(valor)
      .replace("R$", "")
      .replace(/\./g, "")
      .replace(",", ".")
      .trim()
  );
}

const resultados = recomendacoes.map((cliente) => {
  const saldoTexto = cliente.saldo || cliente.saldo_texto || "";
  const saldoNum = cliente.saldo_num || parseBRL(saldoTexto);

  const primeiraOpcao =
    Array.isArray(cliente.opcoes) && cliente.opcoes.length > 0
      ? cliente.opcoes[0]
      : null;

  return {
    json: {
      nome: cliente.nome,
      email: cliente.email,
      perfil: cliente.perfil,
      saldo_texto: saldoTexto,
      saldo_num: saldoNum,
      recomendacao: primeiraOpcao || cliente.recomendacao || null,
      mensagem_base: cliente.mensagem || "",
      contexto_ia: `Cliente ${cliente.nome}, email ${cliente.email}, perfil ${cliente.perfil}, saldo disponível ${saldoTexto}. Mensagem base: ${cliente.mensagem || ""}`
    }
  };
});

return resultados;

const clientes = $('Code in JavaScript2').all();

return items.map((item, index) => {
  const cliente = clientes[index]?.json || {};

  const textoIA =
    item.json.output?.[0]?.content?.[0]?.text ||
    item.json.output?.[0]?.content?.text ||
    item.json.content?.[0]?.text ||
    item.json.text ||
    "";

  const texto = String(textoIA).trim();

  const subject = `Sugestão de Investimento: ${cliente.recomendacao?.produto || "Perfil Personalizado"}`;

  const text_body = texto;

  const html_body = `
    <p>${texto
      .replace(/\n\n/g, "</p><p>")
      .replace(/\n/g, "<br>")}
    </p>
  `.trim();

  return {
    json: {
      ok: true,
      to: cliente.email,
      subject,
      text_body,
      html_body,
      meta: {
        nome: cliente.nome,
        perfil: cliente.perfil,
        saldo: cliente.saldo_texto,
        produto: cliente.recomendacao?.produto || null
      }
    }
  };
});
